window.__dh_data = window.__dh_data || {};
window.__dh_data["az"] = {
  "": "Content-Type: text/plain; charset=UTF-8\nContent-Transfer-Encoding: 8bit\n",
  "title": "Dhammapada",
  "chaps": "Fəsillər",
  "fontsize": "Şrift ölçüsü",
  "chap1": "Qoşa Bəndlər",
  "1": "Dhammalar ağılla şərtlənmişlər, onların ən yaxşı hissəsi – ağıldır, ağıldan yaradılmışlar onlar. Əgər kimsə nəyisə çirkli ağılla danışır və edirsə, onu bədbəxtlik təqib edir, arabanı dartan öküzün izi ilə təkərin getdiyi kimi.",
  "2": "Dhammalar ağılla şərtlənmişlər, onların ən yax­şı hissəsi – ağıldır, ağıldan yaradılmışlar onlar. Əgər kimsə təmiz ağılla danışır və iş görürsə, sə­adət onu izləyir, geri qalmaq istəməyən kölgə kimi.",
  "3": "'O məni təhqir etdi, o məni vurdu, o mənim üzərimdə üstünlük qazandı, o məni heç nəsiz qoydu'. Daxillərində bu cür fikirlər daşıyanlarda nifrət heç zaman durmur.",
  "4": "'O məni təhqir etdi, o, məni vurdu, o mənim üzərimdə üstünlük qazandı, o məni heç nəsiz qoydu'. Daxillərində bu cür fikirlər daşımayanlarda nifrət yoxa çıxır.",
  "5": "Zira, bu dünyada nifrət heç zaman nifrətlə durdurulmur, nifrətin yoxluğu ilə durdurulur o. Budur əzəli dhamma.",
  "6": "Axı çoxları bilmir ki, biz hökmən burada öləcəyik. Bunu bilən kəslərdə isə mübahisələr dərhal kəsilir.",
  "7": "O kəs ki, yalnız ləzzətlərin seyrində yaşayır, hisslərini ram edə bilmir, yeməkdə hədd tanımır, tənbəl və qətiyyətsizdir, - məhz onu Mara sarsıdır, gücsüz ağacı külək sarsıdan kimi.",
  "8": "O kəs ki, ləzzətlərin seyrinə qapılmadan yaşayır, hisslərini nəzarətdə saxlayır, yeməkdə mötədildir, inam və qətiyyətlə doludur,- məhz onu Mara sarsıda bilmir, külək daş-qayanı sarsıda bilmədiyi kimi.",
  "9": "Sarı libas geyən, özü isə çirkabdan təmiz­lən­məyən, həqiqəti, özünü məhdud­laşdır­manı bil­­­məyən kəs sarı libasa layiq deyil.",
  "10": "Lakin çirkabdan azad olmuş, fəzilətlərdə möh­­kəm olan, həqiqət və özünü məhdudlaşdırma ilə dolan kəs, məhz o, sarı libasa layiqdir.",
  "11": "Həqiqəti həqiqətsizlikdə görənlər və həqiqət­sizliyi həqiqət sayanlar heç zaman həqiqətə ça­ta bilməyəcəklər, zira, onların nəsibi yalançı niy­yətlərdir.",
  "12": "Həqiqəti həqiqət və həqiqətsizliyi həqiqətsiz­lik kimi görənlər, onlar həqiqətə çatacaqlar, zira, onların nəsibi həqiqi niyyətlərdir.",
  "13": "Pis damı olan evə yağış necə daxil olursa, pis inkişaf etmiş ağıla da ehtiras eləcə daxil olur.",
  "14": "Yaxşı damı olan evə yağış daxil ola bilmədiyi kimi, yaxşı inkişaf etmiş ağıla da ehtiras daxil ola bilmir.",
  "15": "Bu dünyada da şikayətçidir o, o biri dünyada da. Hər iki dünyada şikayətçidir zülm törədən. Şikayət edir, əzab çəkir o, əməllərinin zülmünü görərək.",
  "16": "Bu dünyada da sevinir o, o biri dünyada da. Saleh əməl sahibi hər iki dünyada sevinir. Sevinir o, sevinib qurtara bilmir, əməllərinin qüsursuzluğunu görərək.",
  "17": "Bu dünyada da əzab çəkir o, o biri dünya da, hər iki dünyada əzab çəkir zülm törədən. 'Bu zülmü mən elədim'- deyə əzab çəkir o. Pis yola düşüncə isə daha çox əzab çəkir.",
  "18": "Bu dünyada da şadlanır o, o biri dünyada da. Hər iki dünyada şadlanır saleh əməl sahibi. 'Bu xeyiri mən elədim!'- deyə şadlanır o. Doğru yola yetişincə isə daha çox şadlanır.",
  "19": "Əgər insan Kitabı hətta əzbər belə bilsə, lakin özü qafildir və ona riayət etmirsə, o, başqasının inəklərini sayan çobana bənzəyir. Müqəddəsliyə aidiyyəti yoxdur onun.",
  "20": "Əgər hətta insan Kitabı az təkrarlayırsa belə, lakin dhammaya uyğun yaşayırsa, ehtirasdan, nifrətdən və cəhalətdən azaddır, həqiqi biliyə və azad ağıla malikdirsə, nə bu dünyada, nə də o biri dünyada bağlılığı yoxdursa, onun müqəddəsliyə aidiyyəti var.",
  "chap2": "Ciddilik",
  "21": "Ciddilik, ölümsüzlüyə aparan yoldur. Yüngüllük, ölümə aparan yoldur. Ciddilər ölmürlər. Yüngüllər ölü kimi bir şeydirlər.",
  "22": "Bunu aydın anlayaraq, müdriklər ciddidirlər. Ciddilikdən alırlar sevinclərini onlar. Nəciblərin zəmisində sevinirlər onlar.",
  "23": "Düşüncəli, inadkar, daima dəyanətli və müdrik olanlar, onlar bağlılıqdan azad və bənzərsiz Nirvanaya yetişənlərdir.",
  "24": "Əgər ciddi adam özünü ilhamlandırarsa, unutqan olmazsa, əgər onun əməlləri təmizdir və o şüurla hərəkət edirsə, özünü məhdudlaşdıra bilir və qanuna uyğun yaşayırsa, onda onun şöhrəti daima artacaqdır.",
  "25": "Qoy, müdrik səylə, ciddiliklə, özünü məhdudlaşdırma və nəzarətlə özünə elə bir ada düzəlt­sin ki, sel dağıda bilməsin onu.",
  "26": "Axmaqlar boş şeylərin, şər müdrikliyin arxasınca gedərlər. Müdrik isə ciddiliyi qiymətli xəzinə kimi qoruyur.",
  "27": "Yüngüllükdən qaçın, ehtirasdan və həzzlərdən çəkinin, zira, yalnız ciddi və düşüncəli olan böyük səadətə qovuşa bilir.",
  "28": "Müdrik, ciddiliklə yüngüllüyü qovanda, o qayğısız, müdrikliyin zirvələrinə yüksələrək qüssə ilə xəstələnmiş bəşəriyyətə dağda duranın düzəndə durana baxdığı kimi, müdrikin səfehə baxdığı kimi baxır.",
  "29": "Yüngüllər içində ciddi, yatanlar içində oyaq olan müdrik, yabını ötən kəhər kimi başqalarından seçilir.",
  "30": "Göy əhli arasında birinciliyi Maqhavan öz ciddiliyi ilə əldə etmişdir. Ciddiliyi tərifləyər, yüngüllüyü isə həmişə lənətləyərlər.",
  "31": "Ciddilikdə məmnunluq tapan, yaxud yüngüllüyə qorxu ilə baxan bhikşu böyük və kiçik düyünləri yandıran alov kimi özünə yol açır.",
  "32": "Ciddilikdə məmnunluq tapan, yaxud yüngüllüyə qorxu ilə baxan bhikşu yıxılmağa qadir deyil: zira, o, Nirvanaya yaxındır.",
  "chap3": "Fikir",
  "33": "Titrəyən, əsən, kövrək və zorla saxlanılan fikri Müdrik oxçunun oxu yönəltdiyi tək yönəldir.",
  "34": "Sudan çıxardılaraq quruya atılmış balıq kimi əsir bu fikir: təki Maranın hökmündən qurtula bilsin.",
  "35": "Zorla saxlanılan, zərif, harda gəldi ilişən fikrin ram edilməsi xeyirdir. Ram edilmiş fikir səadətə aparır.",
  "36": "Qoy, müdrik çətin dərk olunan, son dərəcədə incə, harda gəldi ilişən fikrini qorusun; qorunan fikir səadətə aparır.",
  "37": "Uzaqlarda dolaşan, tənha avaralanan, qeyri-maddi, ürəkdə gizlənən fikirlərini ram edə bilənlər Maradan azad olacaqlar.",
  "38": "Fikri dayanıqsız olanın, həqiqi dhammanı bilməyənin, imanı tərəddüd edənin müdrikliyi kamilləşmir.",
  "39": "Əgər insanın fikirləri dağınıq deyilsə, ağlı qarışmayıbsa, əgər o, xeyir və şəri düşünmürsə, beləcə oyaq olana qorxu yoxdur.",
  "40": "Bu bədənin palçıq olduğunu bilərək, bu fikri qalaya çevirərək, qoy, o, müdriklik silahı ilə Maranın üzərinə atılsın. Və qələbəni qorusun və bağlılıqlardan azad qalsın.",
  "41": "Eh! Bu bədən yerdə uzun yaşamayacaq - nəsibsiz, hissiyyatsız, faydasız, odun kimi.",
  "42": "Düşmən düşməninə, yaxud nifrətli nifrətliyə nə edir etsin, yanlış yönəlmiş fikir daha betərini etmək iqtidarındadır.",
  "43": "Ana, ata, yaxud başqa bir qohum nə edir etsin, doğru yönəlmiş fikir daha yaxşısını etmək iqtidarındadır.",
  "chap4": "Güllər",
  "44": "Bu yerə və Yamanın aləminə və göy əhlinin dünyasına kim qalib gələcək? Yaxşı təlim olunmuş dhamma yolunu kim tapacaq, ağıllı adam gülü tapan kimi?",
  "45": "Şagird qalib gələcək bu yerə, Yamanın aləminə və göy əhlinin dünyasına. Şagird tapacaq yaxşı təlim olunmuş dhamma yolunu, ağıllı adam gülü tapan kimi.",
  "46": "Bu bədənin köpüyə bənzər olduğunu bilən, onun ilğım təbiətini anlayan kəs Maranın güllərlə bəzədilmiş oxlarını sındıracaq və heç zaman ölümü görməyəcəkdir.",
  "47": "Gül dərən, ağlı pərdəli olan insanı isə ölüm oğurlayır, sel yatmış kəndi yuyub aparan təki.",
  "48": "Gül dərən, ağlı pərdəli olan insanı isə ölüm özünə müti edir, o hissi əyləncələrdən doyana qədər.",
  "49": "Necə ki, arı gülü, onun rəngini və ətrini zədələmədən şirələnib uçur, qoy, müdrik də özünü kənddə elə aparsın.",
  "50": "Qoy, o başqalarının nöqsanlarına, elədikləri və eləmədiklərinə baxmasın, özünün elədiklərinə və eləmədiklərinə baxsın.",
  "51": "Yaxşı deyilmiş söz, əgər insan özü ona əməl etmirsə, faydasızdır, xoş rəngli, lakin ətirsiz bir gözəl gül kimi.",
  "52": "Yaxşı deyilmiş söz, əgər insan özü ona əməl edirsə, məhsuldardır, xoş rəngli və ətirli gözəl gül kimi.",
  "53": "Bir topa güldən çoxlu çələng hörmək mümkün olduğu kimi, beləcə ölümlü də doğulanda çoxlu xeyirli əməllər edə bilər.",
  "54": "Güllərin ətri küləyin əksi istiqamətində yayılmır, sandal ağacında da belədir, taqarda da, jasmində də. Salehlərin ətri isə küləyin əksi istiqamətində də yayılır. Xeyirxah insan hər yerə nüfuz edir.",
  "55": "Sandal ağacı yaxud taqara, şanagüllə yaxud vassika – onların ətirləri içərisində ən üstün olanı, xeyirli əməllərin ətridir.",
  "56": "Zəifdir bu ətir, taqaranın və sandal ağacının buraxdığı. Göy əhli arasında əsən xeyirli əməllərin ətri isə ən yaxşısıdır.",
  "57": "Nəciblərin, ciddiliklə dolanların və kamil bilik vasitəsi ilə azad olanların cığırlarını Mara tapa bilmir.",
  "58": "Böyük yola tökülmüş zibil yığınında şirin ətirli və ağılı sadlandıran şanagüllə çiçəyi bitə bildiyi kimi,",
  "59": "beləcə həqiqətən nurlanmışın şagirdi də kor bəsitlər arasında, zibilə bənzər məxluqlar arasında, öz müdrikliyi ilə seçilir.",
  "chap5": "Axmaqlar",
  "60": "Gecə uzundur oyaq qalan üçün, yocana uzundur yorulmuş üçün, sansara uzundur axmaqlar, həqiqi dhammanı bilməyənlər üçün.",
  "61": "Əgər yolçu özünə bənzərinə yaxud daha yaxşısına rast gəlməsə, qoy, o, tənhalıqda möhkəmlənsin: axmaqla dostluq olmur.",
  "62": "'Oğullarım mənim – sərvətim mənim',- beləcə axmaq əzab çəkir. Axı, heç onun özü-özünə sahib deyil. Bəs oğullar hardan? Sərvət hardan?",
  "63": "Öz axmaqlığını bilən axmaq bununla artıq müdrikdir, özünü müdrik sanan axmaq isə həqiqətən də, necə deyərlər,'axmaqdır'.",
  "64": "Əgər axmaq hətta bütün ömrü uzunu müdriklə bağlıdırsa belə, o, dhammanı qaşıq şorbanın dadını bildiyindən artıq bilmir.",
  "65": "Əgər hətta bir anlığına belə ağıllı müdriklə bağlanırsa, o, dhamma ilə sürətlə tanış olur, dil şorbanın dadı ilə tanış olan təki.",
  "66": "Ağılsız olan axmaqlar özləri ilə düşmənlə davranan kimi davranırlar, şər əməl törədirlər, acı meyvələr gətirən.",
  "67": "Pis görülüb o iş ki, onu eləyəndən sonra peşman olurlar və onun meyvəsini ağlanmış üzlə, hıçqıra-hıçqıra qəbul edirlər.",
  "68": "Lakin yaxşı görülüb o iş ki, onu eləyəndən sonra peşman olmurlar və onun meyvəsini sevinc içində və məmnunluqla qəbul edirlər.",
  "69": "Şər yetişməyincə axmaq onu bal sanır. Şər yetişincə isə axmaq dərdə düşür.",
  "70": "Qoy, axmaq aybaay kus otunun ucu ilə yemək yesin. Hər halda o, dhammanı bilənlərin onaltıda bir hissəsinə belə dəymir.",
  "71": "Zira, süd dərhal çürümədiyi kimi, törədilən şər əməl də dərhal meyvələrini göstərmir; küllə örtülü od kimi közərir, bu axmağı təqib edir.",
  "72": "Lakin o zaman ki, axmaq bədbəxtlikdən biliyə sahib olur, onda bilik onun başını partladaraq onun uğurunu məhv edir.",
  "73": "O özünə yaraşmayan mövqeni və bhikşular arasında birinciliyi və monastırlarda hakimiyyəti və digərləri arasında seçilməyi arzulaya bilər.",
  "74": "'Qoy, dünyəvilər də, zahidlər də bilsinlər ki, bunu mən etmişəm. Qoy, onlar bütün işlərində məndən asılı olsunlar', - axmağın niyyəti budur; onun arzusu və təkəbbürü daima artır.",
  "75": "Zira, bir vasitə var-dövlət əldə etməyə aparır, digəri Nirvanaya. Bunu bilən bhikşu, Buddanın şagirdi, şan-şövkətə sevinməz, tənhalığı sevər.",
  "chap6": "Müdriklər",
  "76": "Əgər kimsə qüsurları göstərən və onlara görə qınayan müdriki görmüş olsa, qoy, o beləsinin ardınca getsin, xəzinəni göstərən birisinin ardınca gedən təki. Beləsinin ardınca gedənə yaxşı olacaq, pis olmayacaq.",
  "77": "Qoy, o, məsləhət versin, öyrətsin və şərdən saxlasın. Axı o, xeyirxaha xoş və zalıma naxoş gəlir.",
  "78": "Qoy, heç kim pis dostlarla birləşməsin, qoy, heç kim alçaq insanlarla birləşməsin. Yaxşı insanlara bağlanın. Nəcib insanlara bağlanın.",
  "79": "Dhamma yeyən xoşbəxt yaşayır; təmiz ağıllı müdrik Nəcibin bəyan etdiyi dhammaya daima heyrət edir.",
  "80": "Kanal çəkənlər su buraxırlar, oxçular oxu özlərinə tabe etdirirlər, dülgərlər ağacı özlərinə ram edirlər, müdriklər özlərini sakitləşdirirlər.",
  "81": "Möhkəm qayanı külək yerindən tərpədə bilmədiyi kimi, beləcə müdriklər də söyüş və təriflər altında sarsılmazdırlar.",
  "82": "Dhammaları eşidincə müdriklər göl kimi təmiz olurlar, dərin, təmiz və bulanıqsız.",
  "83": "Salehlər öz yollarını istənilən şəraitdə davam etdirirlər. Xeyirxahlar hətta istəyəndə belə boşboğazlıq etmirlər. Onlara səadət və ya kədər toxunanda isə müdriklər nə onu, nə də o birisini üzə göstərmirlər.",
  "84": "Nə özündən ötrü, nə də başqasından ötrü o, nə oğul, nə var-dövlət, nə də şahlıq istəməz. Qanunsuz yolda o özünə uğur arzulamaz. Qoy, o həmişə nəcib, müdrik və ədalətli olsun.",
  "85": "İnsanlar arasında çox azı qarşı sahilə yan ala bilirlər. Qalan insanlar isə yalnız bu sahildə vurnuxmaqla məşğuldurlar.",
  "86": "Dhamma layiqincə bəyan edildikdə həqiqətən dhammaya riayət edən insanlar isə nə qədər çətin olsa da, ölüm səltənətindən yan keçərək qarşı sahilə yetişə biləcəklər.",
  "87": "Qaranlıq dhammanı tərk edən müdrik, qoy, nurlu dhammanı bəsləsin. Evdən evsizliyə hicrət edərək, qoy, o, tənhalıqda, sevinc üçün ən az yarayan kimi görünə bilən şəraitdə, məmnunluq arasın.",
  "88": "Arzulardan imtina edərək, mülkiyyətdən qurtularaq, qoy, müdrik öz ağlını çirkabdan təmizləsin.",
  "89": "O kəslərin ki, ağlı nurlanmanın əsaslarına layiqincə söykənmişdir, o kəslər ki, bağlılıqlardan imtina etmişlər, azadlığa sevinirlər, öldürülmüş arzularla, işıqla dolu olan o kəslər bu dünyada Nirvanaya çatanlardır.",
  "chap7": "Arhatlar",
  "90": "Səyahəti başa vuran üçün, kədərsiz üçün, hər baxımdan azad üçün, bütün bağları atan üçün ehtiras qızdırması deyilən şey yoxdur.",
  "91": "Müdriklər hicrət edirlər; evdə onlar üçün həzz yoxdur. Öz gölünü tərk edən qu quşları kimi, öz mənzillərini tərk edirlər onlar.",
  "92": "Onlar ehtiyat yığmırlar, qidaya onların düzgün baxışları var, onların nəsibi arzulardan məhrum və heç nə ilə şərtlənməyən azadlıqdır. Onların yolu göydəki quşların uçuşu kimi çətin anlaşılır.",
  "93": "Onun arzuları məhv olmuşdur və o, qidaya bağlı deyil; onun nəsibi arzulardan və şərtlərdən azad olan qurtuluşdur. Onun yolu göydəki quşların uçuşu kimi çətin anlaşılır.",
  "94": "Onun hissləri arabaçının ram etdiyi atlar kimi sakitdirlər. O, təkəbbürdən imtina etmişdir və arzulardan məhrumdur. Beləsinə göy əhli belə həsəd aparır.",
  "95": "Torpaq kimi o da çaşqınlıq tanımır; beləcə comərd olan İndranın sütununa bənzəyir; o, çirkabsız göl kimidir. Beləsində sansaralar olmur.",
  "96": "Onun fikri sakitdir, sözü də sakitdir, əməli də. Beləcə sakit və azad olan kamil bilik yiyəsidir.",
  "97": "O kəs ki, inanmır və yaradılmamışı bilir, bağlılıqları qırmış, təsadüfə son qoymuş, arzulardan imtina etmişdir, həqiqətən ən nəcib insandır.",
  "98": "Kənddə yaxud meşədə, vadidə yaxud təpədə - Arhatlar harda yaşasalar, o yer xoş yerdir.",
  "99": "Meşələr xoşdur. Başqalarının sevinmədiyi yerdə ehtiraslardan məhrumlar sevinərlər, zira, onlar hissi həzzləri axtarmırlar.",
  "chap8": "Min",
  "100": "Eşidincə insanın sakitləşdiyi bir faydalı söz faydasız sözlərdən tərtib olunmuş minlərlə nitqdən yaxşıdır.",
  "101": "Eşidincə insanın sakitləşdiyi yarım ayə faydasız sözlərdən tərtib olunmuş minlərlə ayədən yaxşıdır.",
  "102": "Eşidincə insanın sakitləşdiyi yarım ayə daha yaxşıdır, nəinki kimsə faydasız sözlərdən tərtib olunmuş yüz ayə oxusun.",
  "103": "Əgər birisi döyüşdə min dəfə min nəfərə qalib gəlmiş olsa, başqası isə yalnız özünə qalib gəlsə, məhz bu başqası döyüşdə ən böyük qalibdir.",
  "104": "Həqiqətən, daimi özünü məhdudlaşdırmada yaşayan, özünü ram etmiş insanın özü üzərindəki qələbəsi başqa insanlar üzərindəki qələbədən daha yaxşıdır.",
  "105": "Nə Mara Brahman ilə, nə göy əhli, nə qandharva bu insanın qələbəsini məğlubiyyətə çevirə bilməyəcək.",
  "106": "Qoy, kimsə yüz il ərzində hər ay min dəfə qurbanvermə ayini yerinə yetirsin və qoy, bir başqası özünü kamilləşdirənə heç olmasa bir anlığına təzim etsin. Həqiqətən, belə ehtiram yüz illik qurbanvermədən daha yaxşıdır.",
  "107": "Qoy, insan yüz il meşədə odun qulluğunda dursun və qoy, o bir anlığına da olsa özünü kamilləşdirənə təzim etsin. Həqiqətən, belə ehtiram yüz illik qurbanvermələrdən daha yaxşıdır.",
  "108": "Bu dünyada xeyirxah adam il ərzində sədəqə və nəzir kimi nə qurban versə də, bütün bunlar qara qəpiyə də dəyməz. Saleh həyat tərzi yaşayanlara hörmət daha yaxşıdır.",
  "109": "Mərifətli olan və qocalara həmişə hörmətlə yanaşan insanda dörd dhamma böyüyür: həyat, gözəllik, xoşbəxtlik, qüvvət.",
  "110": "Xeyirxah və özünə dalmışın bir günü qüsurlu və pozğun insanın yüz illik mövcudluğundan daha yaxşıdır.",
  "111": "Müdrikləşmiş və özünə dalmışın bir günü cahil və pozğun insanın yüz illik mövcudluğundan daha yaxşıdır.",
  "112": "Qaynayan enerjiyə malik birisinin bir günü tənbəl və enerjidən məhrum insanın yüz illik mövcudluğundan daha yaxşıdır.",
  "113": "Əvvəli və sonu görmüşün bir günü əvvəli və sonu görməyən insanın yüz illik mövcudluğundan daha yaxşıdır.",
  "114": "Ölümsüz yolu görmüşün bir günü ölümsüz yolu görməyən insanın yüz illik mövcudluğundan daha yaxşıdır.",
  "115": "Ali dhammanı görmüşün bir günü ali dhammanı görməyən insanın yüz illik mövcudluğundan daha yaxşıdır.",
  "chap9": "Şər",
  "116": "Qoy, o, xeyir iş görməyə tələssin; şərdən ağlını qorusun, qoy. Zira, xeyir iş görməyə tələsməyən birisinin ağlı şərdə məmnunluq tapır.",
  "117": "Əgər insan şər iş tutmuşsa belə, qoy, o onu təkrar-təkrar etməsin, onun üzərində qurmasın niyyətlərini. Şərin toplanması kədərlidir.",
  "118": "Əgər insan xeyir iş görmüşsə belə, qoy, o onu təkrar-təkrar eləsin, onun üzərində qursun niyyətlərini. Xeyirin toplanması sevinclidir.",
  "119": "Hətta zalım belə xoş gün görür, nə qədər ki, şər yetişməyib. Lakin şər yetişincə zalım şəri görür.",
  "120": "Hətta saleh belə zülmə məruz qalır, nə qədər ki, xeyir yetişməyib. Lakin xeyir yetişincə, saleh xeyiri görür.",
  "121": "Şər barədə yüngül düşünmə: 'O mənə gəlməyəcək', - demə. Axı bardaq da damlaların düşməsindən dolur. Axmaq şərlə dolur, hətta onu az-az toplasa belə.",
  "122": "Xeyir barədə yüngül düşünmə: 'O mənə gəlməyəcək', - demə. Axı bardaq da damlaların düşməsindən dolur. Ağıllı xeyirlə dolur, hətta onu az-az toplasa belə.",
  "123": "Qoy, o, şərdən yan qaçmağa çalışsın, müşayiətsiz, lakin böyük vara malik tacir təhlükəli yoldan yan qaçan kimi, yaşamaq istəyən zəhərdən qaçan kimi.",
  "124": "Əl yaralı deyilsə, əldə zəhər daşımaq olar. Yarası olmayana zəhər zərər verə bilməz. Özü şər iş tutmayan, şərə məruz qalmır.",
  "125": "Günahsız adama zülm edənə, məsum və qüsursuz insana zülm edənə, məhz belə bir axmağa zülm qayıdır, küləyin əksinə atılmış zərif toz kimi.",
  "126": "Bəziləri ana bətninə qayıdır, zülm edənlər cəhənnəmə düşürlər, salehlər cənnətə, arzulardan məhrum olmuşlar isə Nirvanaya yetişirlər.",
  "127": "Nə göydə, nə okeanın ortasında, nə içinə girilsə, dağın yarğanında, yerdə elə bir yer tapılmaz ki, yaşayan öz şər əməllərinin nəticələrindən yaxa qurtara bilsin.",
  "128": "Nə göydə, nə okeanın ortasında, nə içinə girilsə, dağın yarğanında, yerdə elə bir yer tapılmaz ki, yaşayana ölüm qalib gəlməsin.",
  "chap10": "Cəza",
  "129": "Hamı cəza qarşısında əsir, hamı ölümdən qorxur – özünüzü başqasının yerinə qoyun. Nə öldürmək, nə də ölümə təhrik etmək olmaz.",
  "130": "Hamı cəza qarşısında əsir, həyat hamıya xoş gəlir – özünüzü başqasının yerinə qoyun. Nə öldürmək, nə də ölümə təhrik etmək olmaz.",
  "131": "Kim ki, səadət axtararaq səadət arzulayan məxluqlara cəza verir, o kəs ölümündən sonra səadət almayacaqdır.",
  "132": "Kim ki, səadət axtararaq səadət arzulayan məxluqlara cəza vermirsə, o kəs ölümündən sonra səadət alacaqdır.",
  "133": "Heç kimlə kobud danışma; kimlə kobud danışsan, sənə eyni şeylə cavab verəcəklər. Axı qıcıqlı nitq xoş deyil və qisas sənə toxuna bilər.",
  "134": "Əgər sən sınmış qonq kimi sakitləşmisənsə, sən Nirvanaya çatmısan, səndə qıcıq yoxdur.",
  "135": "Çoban ağacla inəkləri örüşə qovduğu kimi, beləcə qocalıq və ölüm də canlı varlıqların həyatlarını qovurlar.",
  "136": "Şər işlər tutanda axmaq bunu başa düşmür. Ağılsız öz əməllərinin ucbatından odda qovrulan tək əzab çəkir.",
  "137": "Günahsız və korlanmamışlara cəza verən kimsə tezliklə on haldan birinə gəlib çıxır.",
  "138": "Onun başına gələ bilər: acı əzab, bədənin zədələnməsi və ya ağır əziyyət və ya xəstəlik, dəlilik;",
  "139": "yaxud şahın qəzəbi və ya ittiham və ya doğmalarının itirilməsi və ya sərvət itkisi və ya evinin odda yanması.",
  "140": "Bədən dağılanda, axmaq cəhənnəmə düşür.",
  "141": "Nə çılpaq gəzmək, nə dolaşıq saçlar, nə kir, nə oruc, nə quru torpaqda yatmaq, nə toz və çamur, nə çöməlib oturmaq şübhələrə qalib gəlməmiş ölümlünü təmizləyə bilməz.",
  "142": "Qoy, o lap bəzənmiş olsun, lakin əgər o sülh içində yaşayır, sakit, təslim olmuş, nəfsini qoruyandırsa, saleh həyat yaşayır, bütün varlıqlara cəza verilməsini rədd edirsə, o, brahmanadır, o, zahiddir, o, bhikşudur.",
  "143": "Dünyada elə bir insan tapılarmı ki, özünü təvazökarlıqla ram etsin, yaxşı öyrədilmiş at qırmanca ehtiyac hiss eləmədiyi kimi, qısnanmaya ehtiyacı olmasın?",
  "144": "Qırmancla toxunulan, yaxşı təlim görmüş at kimi enerjili və canlı olun. İmanın, xeyirxahlığın və enerjinin, özünə dalmanın və dhamma öyrənmənin köməyi ilə siz, düşüncəlilər, biliklə dolular və davranışlarında qüsursuzlar, bu böyük bəladan qurtulacaqsınız.",
  "145": "Kanal çəkənlər su buraxırlar, oxçular oxu özlərinə tabe etdirirlər, dülgərlər ağacı özlərinə ram edirlər, xeyirxahlar özlərini sakitləşdirirlər.",
  "chap11": "Qocalıq",
  "146": "Bu nə gülüş, bu nə şadlıqdır, o zaman ki, dünya daima od içindədir? Zülmətlə örtülmüşlər, siz niyə nuru axtarmırsınız?",
  "147": "Bu bəzədilmiş şəklə, qüsurla dolu, hissələrdən yığılmış, xəstəhal, içi müəyyənlik və sabitlikdən məhrum fikirlərlə dolu bədənə bax.",
  "148": "Cındırı çıxıb bu bədənin, xəstəlik yuvası, fani; bu çürüməkdə olan qalaq dağılmaqdadır; zira, həyat ölümlə sonuclanır.",
  "149": "Bu maviyə çalan, payız vaxtı ora-bura atılmış balbabaqlara bənzəyən sümükləri görməkdə nə ləzzət var?",
  "150": "Bu qala sümüklərdən düzəldilib, ət və qanla suvanıb; qocalıq və ölüm, aldanış və riya var onda.",
  "151": "Bər-bəzəkli şah arabaları belə köhnəlirlər; beləcə, bədən də qocalığa yaxınlaşır. Lakin nəciblərin dhamması qocalığa yaxınlaşmır; zira, xeyirxahlar onu xeyirxahlara öyrədirlər.",
  "152": "Az bilikli insan öküz kimi qocalır: onun əzələləri böyüyür, biliyi isə artmır.",
  "153": "Mən uğursuzcasına evin inşaatçısını axtara-axtara bir çox doğuluşların sansarasından keçdim. Təkrar-təkrar doğulmaq kədərlidir.",
  "154": "Ey evin inşaatçısı, sən görürsən! Evi bir daha yenidən tikə bilməyəcəksən. Sənin bütün atmaların çürüyüb, damdakı çatma da məhv edilmişdir. Əşyasızlaşma yolunda ağıl arzuların məhvinə nail olmuşdur.",
  "155": "Kimlər ki, saleh həyat yaşamamış, gəncliyində xəzinəyə yetişməmişlər, məhv olurlar, balığı olmayan göldə qoca leyləklər ölən təki.",
  "156": "Kimlər ki, saleh həyat yaşamamış, gəncliyində xəzinəyə yetişməmişlər, sınmış oxlar təki yatırlar, keçmişi xatırlayaraq ah çəkə-çəkə.",
  "chap12": "Öz 'Mən'",
  "157": "Öz 'mən'inin xoş olduğunu bilən, qoy, özünü diqqətlə qorusun. Müdrik gecənin üçdə birini oyaq qalmalıdır.",
  "158": "Qoy, o əvvəlcə özünü lazımi hala gətirsin. Sonra isə başqasını da öyrətmək olar. Müdrik yoldan azmayacaq.",
  "159": "Başqasına öyərətdiyinə özü də əməl etsin. Özünü tam ram edərək o, başqalarını da ram edə bilər. Həqiqətən də özünü ram etmək çətindir.",
  "160": "Axı öz 'mən'i özünə ağadır, daha kim ağa ola bilər ki? Öz 'mən'ini tam təslim edən insan çətin tapılan ağanı tapmış olur.",
  "161": "Özüdoğulan, özüyaranan şəri özün eləmisən. O, axmağa qalib gəlir, almaz qiymətli daşa qalib gələn kimi.",
  "162": "Lap pis xasiyyəti olan kəs özü ilə düşmənin ona arzulaya biləcəyi tərzdə davranır. O, sal ağacını saran maluvanı xatırladır.",
  "163": "Pis və özü üçün zərərli işləri görmək asandır. Yaxşı və faydalı işləri görmək isə son dərəcə çətindir.",
  "164": "Qüsurlu baxışlara görə nəcib, dhamma əsasında yaşayan Arhatların təliminə nifrət edən axmaq katthaka kimi meyvə verir, yalnız özünü məhv etməklə.",
  "165": "Zira insan zülmü özü edir, özü də özünü çirkaba bulaşdırır. Zülmü eləməyən də özüdür və özünü təmizləyən də. Təmizlik və çirkab insanın özü ilə bağlıdır. Heç kim başqasını təmizləyə bilməz.",
  "166": "Qoy, o öz xeyirini az sanmasın, başqasının xeyiri nə qədər böyük olursa-olsun. Öz xeyirini dərk edərək, qoy, o, ali xeyirə sadiq olsun.",
  "chap13": "Dünya",
  "167": "Alçaq dhammaya riayət etmə! Yelbeyin yaşama! Saxta baxışlara riayət etmə! Mövcudluğu artırma!",
  "168": "Qalx! Yelbeyin olma! Xeyirli dhammaya riayət elə.",
  "169": "Dhammaya riayət edən bu dünyada xoşbəxt yaşayır, hətta o birində də.",
  "170": "Dünyaya qovuqcuğa baxan kimi, ilğıma baxan kimi baxanları ölüm şahı görmür.",
  "171": "Gedin alabəzək şah arabasına bənzər bu dünyaya baxın. Səfehlərin çabaladığı yerdə müdrikin heç bir bağlılığı yoxdur.",
  "172": "Əvvəl yüngül olan sonra ciddi olursa, bu dünyanı buludlardan qurtulmuş ay kimi işıqlandırır.",
  "173": "Törətdiyi şərin kəffarəsini xeyir işlə verən kəs, bu dünyanı buludlardan qurtulmuş ay kimi işıqlandırır.",
  "174": "Kordur bu dünya. Dünyada yalnız az bir qisim aydın görə bilir. Tordan qurtulmuş quş kimi, yalnız az bir qisim cənnətə düşür.",
  "175": "Günəşin yolu ilə səyahət edərlər qu quşları; göydə onlar iddhinin köməyi ilə səyahət edərlər. Müdriklər Maranı qoşunu ilə birlikdə məğlub edərək tərk edərlər dünyanı.",
  "176": "Yalan danışan, axirətdən imtina edən, bircə dhammaya saymazlıq edən insanın törədə bilməyəcəyi şər yoxdur.",
  "177": "Həqiqətən, simiclər göy əhlinin dünyasına düşmürlər; səfehlər, həqiqətən, sədəqə verməyi tərifləmirlər. Müdrik isə verərkən sevinir: axı buna görə o, o biri dünyada xoşbəxtdir.",
  "178": "Sotapattinin meyvəsi yer hakimliyindən və ya göyə yüksəlməkdən – bütün dünyanın hökmdarı olmaqdan daha yaxşıdır.",
  "chap14": "Nurlanmış",
  "179": "Bu cığırsızı, nurlanmışı, sonsuz sferaların sahibini, qələbəsi məğlubiyyətə çevrilməyəni və təslim olmuş ehtirası bir daha bu dünyada davam eləməyəcək birisini siz hansı cığırla aparacaqsınız?",
  "180": "Bu cığırsızı, nurlanmışı, sonsuz sferaların sahibini, onu tələyə salacaq bağlılığı, yoldan çıxaracaq arzusu olmayan birisini siz hansı cığırla aparacaqsınız?",
  "181": "Dərin fikirlərlə dolu olan nurlanmışlara hətta göy əhli belə həsəd aparır, azadlığın sakitliyindən həzz alanlara, zikrə qapılanlara, müdriklərə.",
  "182": "İnsan olmaq çətindir; ölümlülərin həyatı çətindir; həqiqi dhammanı dinləmək çətindir; nurlanmışın doğulması çətindir.",
  "183": "Zülm etməmək, xeyirə nail olmaq, ağlını təmizləmək – nurlanmışların elmi bundan ibarətdir.",
  "184": "Dözüm, səbr ali zahidlik, ali Nirvanadır, - deyirlər nurlanmışlar, - zira, başqalarına zərər verən tərki-dünya deyil, başqasını incidən – zahid deyil.",
  "185": "Praktimokşaya müvafiq olaraq, təhqir etməmək, zərər verməmək və nəfsin pəhrizi, qidada mötədillik, tənha yaşamaq, ali zikrlərə sadiqlik – nurlanmışların təlimi bundan ibarətdir.",
  "186": "Hətta qızıl pul yağmuru belə ehtiraslara məmnunluq gətirməyəcək. Müdrik olan bilir: ehtiraslar xəstədirlər və onlarda elə bir sevinc də yoxdur.",
  "187": "O hətta səmavi həzzlərdə belə məmnunluq tapmır. Tam nurlanmış şagird yalnız arzunun olmamasına sevinir.",
  "188": "Qorxudan əzab çəkən insanlar hər bir sığınacağa müraciət edərlər: dağlara, meşələrə, meşədəki ağaclara, qəbirlərə.",
  "189": "Lakin axı belə bir sığınacaq da təhlükəsiz deyil, belə bir sığınacaq da ən yaxşısı deyil. Belə bir sığınacağa sığınan bütün bəlalardan qurtulmur.",
  "190": "O kəs ki, Buddada, Dhammada və Sanqhada sığınacaq tapmışdır, əsl biliyə sahib olan o kəs, Dörd nəcib həqiqəti görür.",
  "191": "Zülm, zülmün mənşəyi və zülmün aradan qaldırılması və Nəcib səkkizli yol, zülmün durdurulmasına aparan.",
  "192": "Bax belə bir sığınacaq təhlükəsizdir, belə sığınacaq ən yaxşısıdır. Belə sığınacağa yetişən bütün bəlalardan qurtulur.",
  "193": "Nəcib insanı tapmaq çətindir: o hər yerdə doğulmur. Lakin belə müdrikin doğulduğu yerdə xoşbəxt nəsil çiçəklənir.",
  "194": "İlahi rəhmət var nurlanmışların doğuluşunda, ilahi rəhmət var həqiqi dhamma təlimində, ilahi rəhmət var sanqhanın razılığında, ilahi rəhmət var razılıqda yaşayanların zahidliyində.",
  "195": "Hörmətə layiq olanlara (istər nurlanmışlar olsun, istər şagirdlər) hörmət edən, maneəni aşmışlara, qəm və şikayətdən qurtulmuşlara,",
  "196": "azadlığa çatmışlara və qorxubilməzlərə hörmət edən kəsin məziyyətlərini heç kimə sadalamaq mümkün deyil.",
  "chap15": "Səadət",
  "197": "O! Biz çox xoşbəxt yaşayırıq, düşmənçilik edənlər içində düşmənçilik etməyənlər, düşmənçilik edən insanlar içində yaşayırıq biz, düşmənçilik etməyənlər.",
  "198": "O! Biz çox xoşbəxt yaşayırıq, xəstələr içində xəstə olmayanlar, xəstə insanlar içində yaşayırıq biz, xəstə olmayanlar.",
  "199": "O! Biz çox xoşbəxt yaşayırıq, üzülənlər içində üzüntü bilməyənlər; üzülən insanlar içində yaşayırıq biz, üzüntü bilməyənlər.",
  "200": "O! Biz çox xoşbəxt yaşayırıq, baxmayaraq ki, heç nəyimiz yoxdur. Biz sevinclə qidalanacağıq, işıq saçan göy əhli kimi.",
  "201": "Qələbə nifrət yaradır; məğlub olmuş qüssədə yaşayır. Səadətdə yaşayır sakit olan, qələbədən və məğlubiyyətdən imtina edərək.",
  "202": "Ehtirasdan böyük alov yoxdur; nifrətdən böyük bəla yoxdur; bədəndən böyük fəlakət yoxdur; sakitliyə bərabər səadət yoxdur.",
  "203": "Aclıq ən böyük xəstəlikdir; bədən ən böyük acıdır; bu barədə həqiqi biliyə malik olan üçün Nirvana ən böyük xeyirdir.",
  "204": "Sağlamlıq ən böyük qələbədir; məmnunluq ən böyük xəzinədir; etibar ən yaxşı qohumdur; Nirvana ən böyük xeyirdir.",
  "205": "Tənhalığın şirinliyini və sakitləşmənin şirinliyini dadaraq, qorxu və günahdan o kəs qurtulur ki, o, dhammanın müqəddəsliyini duyur.",
  "206": "Nəciblərə baxmaq xoşdur; onların cəmiyyətində olmaq xeyirdir. Səfehləri görməyən kəs qoy, həmişə xoşbəxt olsun.",
  "207": "Zira, səfehlərin cəmiyyətində dolaşan uzun müddət əzab çəkir. Səfehlərlə olmaq düşmənlə olmaq kimidir, həmişə bədbəxtlik gətirir, müdriklərlə olmaq isə səadətdir – qohumlarla görüş kimi.",
  "208": "Ona görə də ay ulduz yolu ilə getdiyi kimi, müdrikin, bilənin və çox elmlinin, çox şeyi yaşamışın, möminin, nəcibin - bax belə bir yaxşı və ağıllı insanın dalınca getmək lazımdır.",
  "chap16": "Xoş Olan",
  "209": "Özünü vurnuxmaya həsr edən və özünü düşüncələrə həsr etməyən, məqsədi unutmuş, həzlərdən yapışan özünə dalmışa həsəd aparır.",
  "210": "Xoş olana bağlanma, xoş olmayana isə heç bağlanma. Xoş olanı görməmək və xoş olmayanı isə görmək zülmdür.",
  "211": "Odur ki, xoş olanı etməyin; zira, xoş olanla ayrılmaq ağrılıdır. Xoş olan və xoş olmayandan imtina etmiş üçün bağlar yoxdur.",
  "212": "Xoş olandan qəm doğulur, xoş olandan qorxu yaranır; xoş olandan qurtulmuş qəm nədir bilməz, qorxu hardan olsun?",
  "213": "Meyldən qəm doğulur, meyldən qorxu yaranır; meyldən qurtulmuş qəm nədir bilməz, qorxu hardan olsun?",
  "214": "Bağlılıqdan qəm doğulur, bağlılıqdan qorxu yaranır; bağlılıqdan qurtulmuş qəm nədir bilməz, qorxu hardan olsun?",
  "215": "Ehtirasdan qəm doğulur, ehtirasdan qorxu yaranır; ehtirasdan qurtulmuş qəm nədir bilməz, qorxu hardan olsun?",
  "216": "Arzudan qəm doğulur, arzudan qorxu yaranır; arzudan qurtulmuş qəm nədir bilməz, qorxu hardan olsun?",
  "217": "Yaxşılıq və bəsirətlə dolu, dhammada dəyanətli olan və doğru danışan, borcunu yerinə yetirən – beləsini xalq xoş olan sayır.",
  "218": "Fikri həzzlərə bağlanmamış, daxilində deyilə bilməyənin arzusu doğulmuş (və qoy, o həm də idrakla dolu olsun) uddhamsota çağırılır.",
  "219": "Qohumlar, dostlar və tanışlar uzun müddət olmayan və çox uzaqlardan sağ-salamat qayıtmış birisini salamlayarkən sevinərlər.",
  "220": "Xeyir əməllər bu dünyadan digərinə köçmüş xeyirxah insanı qohumlar öz yaxınlarını qarşıladıqları kimi qarşılayarlar.",
  "chap17": "Qəzəb",
  "221": "Qoy, o, qəzəbdən imtina etsin, qoy, o, təkəbbüründən əl çəksin, qoy, o, bütün bağlılıqlarına qalib gəlsin. Ad və formaya bağlı olmayana heç bir bədbəxtlik üz vermir.",
  "222": "Oyanmış qəzəbini yoldan çıxmış arabanı saxlayan kimi saxlayanı mən arabaçı adlandırıram; qalanlar isə sadəcə yüyən tuturlar.",
  "223": "Qoy, o, qəzəbə qəzəbin yoxluğu ilə, xeyirli olmayana xeyirli olanla qalib gəlsin, qoy, o, simicliyi səxavətlə, yalanı həqiqətlə üstələsin.",
  "224": "Həqiqəti söylə, qəzəbə uyma; səndən istəyirlərsə, az bir şey olsa belə, ver. Bu üç şərtlərin köməyi ilə göy əhlinə yaxınlaşmaq olar.",
  "225": "Heç kimi incitməyən, həmişə ölümlü bədənə malik olan müdriklər dəyişməz yerə gedirlər və ora gələndə, onlar əzab çəkmirlər.",
  "226": "Daima oyaq olan, gecə və gündüz öyrənən və Nirvanaya can atanın arzuları tədricən yox olur.",
  "227": "Ey Atula, bu, bir köhnə məsəldir və təkcə bizim zaman üçün deyilməyib: 'Onlar sakit oturanı qınayarlar, çox danışanı da, qədərində danışanı da qınayarlar onlar'. Dünyada elə bir şey yoxdur ki, onlar onu qınamasınlar.",
  "228": "Yalnız qınanmağa yaxud yalnız təriflənməyə layiq insan olmayıb, yoxdur, heç zaman da olmayacaq.",
  "229": "O kəs ki, davranışında qüsursuzdur, müdrikdir, bilik və məziyyətlərlə doludur, beləsini günbəgün müşahidə etdikcə müdriklər tərifləyərlər.",
  "230": "Cambu çayının qızılından hazırlanmış sikkə kimi olanı kim qınaya bilər? Onu hətta göy əhli belə tərifləyər: Brahmanın özü onu tərifləmişdir.",
  "231": "Bədənin günahlarından çəkin, bədənlə bağlı hər şeydə pəhrizkar ol, bədənin günahlarından qurtulduqdan sonra bədənin günahsızlığını qoru.",
  "232": "Sözün günahlarından çəkin, sözlə bağlı hər şeydə pəhrizkar ol, sözün günahlarından qurtulduqdan sonra sözün günahsızlığını qoru.",
  "233": "Ağlın günahlarından çəkin, ağılla bağlı hər şeydə pəhrizkar ol, ağlın günahlarından qurtulduqdan sonra ağlın günahsızlığını qoru.",
  "234": "Müdriklər bədəndə pəhrizkardırlar; onlar həmçinin sözdə də pəhrizkardırlar; müdriklər ağılda pəhrizkardırlar; onlar, həqiqətən, hər şeydə pəhrizkardırlar.",
  "chap18": "Çirkab",
  "235": "Solmuş yarpaq kimisən sən indi və Yamanın elçiləri dalınca gəlmişlər. Və sən ölümün astanasında dayanmısan. Və sənin yola heç bir ehtiyatın yoxdur.",
  "236": "Özünə ada yarat, səylə mübarizə apar, müdrik ol. Çirkabdan təmizlənərək, qüsursuz halda, sən nəciblərin göy səltənətinə yetişəcəksən.",
  "237": "Budur, həyatın sona çatmışdır. Yamaya yaxınlaşmısan, lakin sənin hətta evin belə yoxdur. Və yola ehtiyatın belə yoxdur.",
  "238": "Özünə ada yarat, səylə mübarizə apar, müdrik ol! Çirkabdan təmizlənərək, qüsursuz halda, sən bir daha doğulma və qocalıqla üzləşməyəcəksən.",
  "239": "Tədricən, az-az, vaxtaşırı müdrik öz üzərindən çirki çırpmalıdır, zərgər üstündəki zərləri çırpan kimi.",
  "240": "Dəmirdə yaranan pas onu yediyi kimi (hərçənd, onun özündən yaranmışdır), beləcə şəxsi əməllər də dhonanı aşan insanı bədbəxtliyə gətirib çıxarır.",
  "241": "Yazı çirklənir, onu təkrarlamayanda; evlər çirklənirlər, onlara baxmayanda; gözəllik tənbəlliklə çirklənir; yüngüllük ayıq insanın çirkidir.",
  "242": "Qadının pis hərəkəti çirkdir; verənin simicliyi çirkdir; həm bu dünyada, həm də o dünyada şər dhammalar çirklidirlər.",
  "243": "Lakin hər şeydən çirkli olan isə cəhalət çirkidir, çirklərin ən pisi; bu çirkdən azad olduqda siz, ey bhikşular, çirkdən qurtulmuş olacaqsınız!",
  "244": "Həyasız olana yaşamaq asandır, qarğa kimi həddini bilməyən, sırtıq, düşüncəsiz, pozğun olana.",
  "245": "Lakin təvazökar olana yaşamaq çətindir, daima təmiz olanı axtarana, tərəfsizə, soyuqqanlıya, bəsirətliyə, həyatı təmiz olana.",
  "246": "Həyatı məhv edən və yalan danışan, bu dünyada ona verilməyəndən yapışan,",
  "247": "və başqasının arvadının yanına gedən, əyyaşlıq edən, bu dünyada öz kökünü qazıyandır.",
  "248": "Bunu bil, ey insan! Şər dhammalar sərhəd tanımır. Və qoy, simiclik və dhammanın yoxluğu səni uzun müddətə şərə bağlamasın.",
  "249": "İnsanlar imanlarına müvafiq verirlər, nə qədər lazım bilirlərsə, o qədər. Başqalarına nəsib olan yeməyə və içməyə həsəd aparan kəs isə nə gündüz, nə də gecə zikrə nail ola bilmir.",
  "250": "Həsədi məhv olmuş, kökündən qoparılmış, ləğv edilmiş kimsə isə gündüz də, gecə də zikrə nail ola bilər.",
  "251": "Ehtirasa bərabər atəş yoxdur, qəzəbə bərabər tutma yoxdur, aldanışa bərabər tor yoxdur, arzuya bərabər çay yoxdur.",
  "252": "Başqalarının günahlarını görmək asandır, özününkülərini isə, əksinə, çətindir. Zira, özgə günahlarını kəpək kimi aləmə səpərlər; özünküləri isə, əksinə, gizlədərlər, mahir fırıldaqçı bəd düşmüş zəri gizlədən kimi.",
  "253": "Özgə günahlarını güdən və daima qıcıqlanmış olanın arzuları artır; arzuların məhvindən uzaqdır o.",
  "254": "Göydə yol yoxdur; bizdən kənarda zahid yoxdur. İnsanlar illüziyalarda sevinc axtarırlar, Tathaqatlar illüziyalardan azaddırlar.",
  "255": "Göydə yol yoxdur; bizdən kənarda zahid yoxdur. Əbədi sankhara yoxdur; nurlanmışlarda daimilik yoxdur.",
  "chap19": "Dhammaya Riayət Edən",
  "256": "Tez-tələsik məqsədə atılan dhammaya riayət edən deyil. Müdrik isə həm bunu, həm də o birini tərəziyə qoyur: doğrunu və doğru olmayanı.",
  "257": "O, başqalarını zor tətbiq etmədən aparır, dhammaya müvafiq olaraq, ehtirassız. Dhammanı qoruyanı, müdrik olanı 'dhammaya riayət edən' adlandırırlar.",
  "258": "Çox danışdığına görə deyil ki, o müdrikdir. Sakit olanı, nifrətdən azad olanı, qorxubilməzi 'müdrik' adlandırırlar.",
  "259": "Çox danışdığına görə deyil ki, o, dhammaya bələddir. O kəs ki, dhammaya qarşı sayğısız deyil, o kəs ki, az savadlı olsa belə, onu bütün bədəni ilə hiss edir, o, həqiqətən, dhammaya bələddir.",
  "260": "Başı ağardığına görə deyil ki, o, böyükdür. O, qoca yaşlarındadır, lakin onu 'əbəs yerə qocalmış' adlandırırlar.",
  "261": "O kəsdə ki, həqiqət və dhamma, özününü məhdudlaşdırma, təslimiyyət var, o kəs ki, qüsursuz və müdrikdir, onu 'böyük' adlandırırlar.",
  "262": "Paxıl, xəsis, sürüşkən insan təkcə bəlağət yaxud gözəl sifət hesabına cəlbedici olmur.",
  "263": "O kəsdə ki, bu məhv edilmişdir, kökündən qoparılmışdır, ləğv edilmişdir, o kəs ki, müdrikdir və nifrətdən imtina etmişdir, onu 'cəlbedici' adlandırırlar.",
  "264": "Sözəbaxmaz və yalançı təkcə qırxılmış başa görə zahid olmur. Bu nə zahiddir, əgər o simicdirsə və arzularla doludursa?",
  "265": "Lakin o kəs ki, şəri tamamilə tabe etdirir, həm balacasını, həm böyüyünü, o kəsi 'zahid' adlandırırlar; zira, o, şəri sakitləşdirmişdir.",
  "266": "O, ona görə bhikşu deyildir ki, başqalarından sədəqə istəyir. Bütün dhammanı öyrənmədən bhikşu olmurlar.",
  "267": "O kəs ki, bu dünyada xeyir və şərdən yüksəkdə durur, yaxud saleh həyat tərzi sürür, kim ki, burada bilikli yaşayır, məhz beləsini 'bhikşu' adlandırırlar.",
  "268": "Axmaq, cahil hətta susmağa riayət edirsə belə muni olmur. O müdrik ki, tərəziyə malik kimi yaxşını seçir və pisdən yayınır, muni odur; məhz ona görə də o munidir.",
  "269": "Bu dünyada həm bunu, həm də onu tərəziyə qoyan, məhz o, 'muni' çağırılır.",
  "270": "O, nəcib deyil, əgər canlı məxluqlar üzərində zorakılıq edirsə. Onu onda nəcib adlandırırlar ki, o, heç bir canlı məxluq üzərində zorakılıq etmir.",
  "271": "Yalnız itaətlə və rituallarla və ya həmçinin çox elmliliklə yaxud özünədalma ilə yaxud tənha gecələmə ilə mən adi dünyəvilər üçün əlçatmaz olan rahatlığa yetişə bilməyəcəm!",
  "272": "Ey bhikşu! Məgər siz arzularınızın məhvinə nail olmadan məmnun ola bilərdinizmi?",
  "chap20": "Yol",
  "273": "Yolların ən yaxşısı səkkizlidir; həqiqətlərdən ən yaxşısı dörd sözdür; dhammalardan ən yaxşısı ehtirasların məhvidir; ikiayaqlılardan ən yaxşısı bəsirətli olandır.",
  "274": "Yol budur və görməni təmizləmək üçün başqası yoxdur. Onunla gedin. Başqa hər şey Maranın vəsvəsəsidir.",
  "275": "Onunla gedərək əzablara son qoyacaqsınız. Bu yolu mən bəyan etdim, tikanları aradan qaldırmağı öyrənincə.",
  "276": "Özünüz cəhd göstərməlisiniz. Tathaqatlar (buddalar) yeganə müəllimlərdir. Bu yolla gedənlər və özünə dalanlar Maranın buxovlarından qurtulacaqlar.",
  "277": "'Bütün yaradılmışlar keçicidirlər'. Buna müdrikcəsinə baxanlarda ağrı azalır. Təmizlənməyə aparan yol budur.",
  "278": "'Bütün yaradılmışlar ağrı və acı deməkdirlər'. Buna müdrikcəsinə baxanlarda ağrı azalır. Təmizlənməyə aparan yol budur.",
  "279": "'Bütün formalar qeyri-realdırlar'. Buna müdrikcəsinə baxanlarda ağrı azalır. Təmizlənməyə aparan yol budur.",
  "280": "Qalxmaq zamanı yetişəndə qalxmayan; cavanlığa və qüvvətə rəğmən tənbəl olan; qətiyyəti və fikri cılız olan - belə qafil və tənbəl müdrikliyin yolunu tapmayacaqdır.",
  "281": "Sözünə nəzarət edən, öz ağlını tam sakitləşdirmiş insan, qoy, o, bədəni ilə pis heç nə eləməsin! Qoy, o, üç əməl yolunu təmiz saxlasın və müdriklərin göstərdiyi cığıra çatsın.",
  "282": "Həqiqətən, düşüncədən müdriklik doğulur, düşüncəsizlikdən müdrikliyin məhvi. Həyata və həyatın məhvinə aparan bu ikili yolu bilərək qoy, o, elə etsin ki, müdriklik artmaqda olsun.",
  "283": "Meşəni qırın, təkcə bir ağacı yox. Qorxu meşədən yaranır. Meşəni də, kolluğu da qırandan sonra, ey bhikşular, siz azad olacaqsınız.",
  "284": "Kişinin qadınlara qarşı arzusu ləğv olmayıbsa, lap az miqdarda belə qalıbsa, onun ağlı bağlıdır, anasının südünü əmən dana kimi.",
  "285": "Arzunu qopart, payız şanagülləsini əllə qopardan kimi. Sakitlik yolu ilə Suqatanın göstərdiyi Nirvanaya doğru get.",
  "286": "'Burda yağışlar zamanı yaşayacağam, burda isə yayda və qışda' - axmaq belə düşünür. O, təhlükə barədə düşünmür.",
  "287": "Uşaqlarda və mal-qarada başını itirmiş belə insanı ölüm oğurlayır, yatmış kəndi sel aparan təki.",
  "288": "Nə uşaqlar, nə atası və nə də qohumları ölümün yaxaladığı kəsi müdafiə edə bilməzlər. Doğmalarda müdafiə tapmaq mümkün deyil.",
  "289": "Bu həqiqəti bilərək, qoy, daxilən təmkinli müdrik tez özü üçün Nirvanaya aparan yolu təmizləsin.",
  "chap21": "Müxtəlif",
  "290": "Əgər balaca xoşbəxlikdən imtina böyük səadəti görməyə imkan verirsə, qoy, müdrik balaca xoşbəxtlikdən imtina etsin, böyük səadəti düşünərək.",
  "291": "Başqalarına əzab verərək özünə səadət axtaran, nifrət torlarında dolaşaraq nifrətdən azad olmur.",
  "292": "Axı görülməli iş təxirə salınır, görülməsi gərəkməyən isə, əksinə, görülür. Belə qafil və təkəbbürlülərin arzuları artır.",
  "293": "Lakin o kəslərin ki, tam toparlanmış ağlı daima bədənə yönəlmişdir, onlar görülməsi gərəkməyən şeylərin ardınca düşmürlər, görüləsi şeyləri səylə görürlər. Belə müdrik və diqqətlilərin arzuları yoxa çıxır.",
  "294": "Ana və atanı və kşatri kastasından olan iki padşahı öldürərək, şahlığı təbəələri ilə birlikdə məhv edərək brahmana təmkinlə gedir.",
  "295": "Ana və atanı və brahmana kastasından olan iki padşahı öldürərək, üstəlik, beşinci olaraq pələng-insanı da öldürüb brahmana təmkinlə gedir.",
  "296": "Böyük ayıqlığa malik olanlar, Qautamanın şagirdləri, həmişə oyaq olurlar. Gecə də, gündüz də onların fikirləri daima Buddaya yönəlmişdir.",
  "297": "Böyük ayıqlığa malik olanlar, Qautamanın şagirdləri, həmişə oyaq olurlar. Gecə də, gündüz də onların fikirləri daima Dhammaya yönəlmişdir.",
  "298": "Böyük ayıqlığa malik olanlar, Qautamanın şagirdləri, həmişə oyaq olurlar. Gecə də, gündüz də onların fikirləri daima Sanqhaya yönəlmişdir.",
  "299": "Böyük ayıqlığa malik olanlar, Qautamanın şagirdləri, həmişə oyaq olurlar. Gecə də, gündüz də onların fikirləri daima bədənə yönəlmişdir.",
  "300": "Böyük ayıqlığa malik olanlar, Qautamanın şagirdləri, həmişə oyaq olurlar. Gecə də, gündüz də onların ağılları daima zorakılıqsızlığa sevinir.",
  "301": "Böyük ayıqlığa malik olanlar, Qautamanın şagirdləri, həmişə oyaq olurlar. Gecə də, gündüz də onların ağılları daima düşünməyə sevinir.",
  "302": "Dünyanın tərzini buraxmaq çətindir, dünyaya sevinmək çətindir; monastrda həyat çətindir, evdə həyat acıdır; səndən fərqlilərlə yaşamaq çətindir, fəqir qərib acılar içindədir. Bu səbəbdən qoy, heç kəs fəqir qərib olmasın və acılar içində qalmasın.",
  "303": "İnam və salehliklə dolmuş olana, şöhrət və dövlət sahibinə, harda olsa, hər yerdə hörmət bəsləyərlər.",
  "304": "Salehlər uzaqdan bərq vurarlar, qarlı dağlar tək. Zalımları isə heç yaxından da görmək olmur, gecə atılan oxları görmək mümkün olmadığı kimi.",
  "305": "Tənhalıqda oturan, tənhalıqda yatan, tənhalıqda gəzişən, fəaliyyətli olan və özü özünün qabağını alan kəs, qoy, meşədə sevinsin.",
  "chap22": "Cəhənnəm",
  "306": "Yalan danışan və həmçinin eləyəndən sonra 'Mən eləmədim' deyən kəs cəhənnəmə düşür. Axı o da, digəri də ölümdən sonra bərabərdirlər; alçaq əməllər sahibləri o dünyada bərabərdirlər.",
  "307": "Boyunları sarıya bürünənlərin bir çoxları dhammaya pis riayət edirlər və hədlərini qoruyan deyillər. Alçaqlar öz alçaq əməlləri ucundan cəhənnəmdə doğulurlar.",
  "308": "Alov kimi qızğın dəmir kürəni udmaq daha yaxşıdır kafir və həddi aşana, nəinki ölkənin zəkatından istifadə etmək.",
  "309": "Qonşunun arvadını istəyən qafil insan dörd şeyə sahib olacaq: şərəfsizlik, yuxusuzluq, üçüncüsü, cəza, dördüncüsü, cəhənnəm.",
  "310": "Şərəfsizlik və pis yol; qorxmuşun (kişinin) qorxmuşla (qadınla) qısa ləzzəti və padşahın ağır cəzası. Odur ki, qoy, insan qonşunun arvadına yol axtarmasın.",
  "311": "Ehtiyatsız tutulduqda kus otu əli kəsdiyi kimi, düzgün sürülmədikdə zahid həyatı da cəhənnəmə aparır.",
  "312": "Qafil görülmüş əməl, yerinə yetirilməyən əhd, tərəddüdlü mərifət – bütün bunlar böyük mükafat gətirmir.",
  "313": "Nəsə görülməlidirsə, onu qətiyyətlə gör. Zira, qafil yolçu daha çox toz qaldırır.",
  "314": "Pis görülmüş əməldən görülməmiş əməl yaxşıdır; zira, pis əməl yada düşdükcə əzab verir. Xeyirli əməl yaxşı görülmüş əməldir; zira, onu gördükdən sonra peşman olmursan.",
  "315": "Daxildən və xaricdən qorunan sərhəd şəhəri kimi qoru özünü. Vaxt itirmə, zira, vaxtı itirmişlər cəhənnəmdə kədərə düşürlər.",
  "316": "Yanlış baxışlara riayət edənlər, utanması gərəkməyən şeylərdən utananlar və utanılası şeylərdən utanmayanlar pis yola düşürlər.",
  "317": "Yanlış baxışlara riayət edənlər, qorxmaq lazım gəlməyəndə təhlükə görənlər və qorxmaq lazım gələndə təhlükəni görməyənlər pis yola düşürlər.",
  "318": "Yanlış baxışlara riayət edənlər, qadağanın olmadığı yerdə qadağa görənlər və qadağanın olduğu yerdə qadağanı görməyənlər pis yola düşürlər.",
  "319": "Doğru baxışlara riayət edənlər, qadağa olunmuşu qadağa olunmuş, qadağa olunmamışı qadağa olunmamış kimi bilənlər doğru yola düşürlər.",
  "chap23": "Fil",
  "320": "İnsanların çoxu xəstə təbiətlidir və mən təhqirlərə səbr edəcəm, döyüşdə fil yaydan atılmış oxa dözdüyü kimi.",
  "321": "Ram edilmişi döyüşə aparırlar; şah ram edilmişin üzərinə yüksəlir. Təhqirlərə səbr edən ram edilmiş insanların ən yaxşısıdır.",
  "322": "Ram edilmiş qatırlar və nəcib sindh atları və iri fillər yaxşıdır. Lakin özünü ram etmiş daha yaxşıdır.",
  "323": "Zira özünü hədlər və çalışmalarla ram etmişin gəlib çıxacağı əlçatmaz ölkəyə bu heyvanlarla yetişə bilməzsən.",
  "324": "Dhanapalaka adlı fili saxlaya bilməzsən, onun gicgahlarından zəhərli maye axdığı zaman. Bağlı halda o, bir tikə də yemir: fil, fil meşəsinin həsrətini çəkir.",
  "325": "Tənbəl, acgöz və yatağan olan, yerində axta donuz kimi qurcalanan axmaq təkrar-təkrar doğulur.",
  "326": "Bu ağıl əvvəllər kefi istədiyi kimi, xoşuna gəldiyi kimi, bildiyi kimi avaralanmışdır. İndi isə mən onu möhkəm saxlayacam, çarvadar qızmış fili saxlayan təki.",
  "327": "Yelbeyin olmayın, fikirlərinizə göz qoyun! Pis yoldan çıxardın özünüzü, palçığa batmış fil özünü çıxaran kimi.",
  "328": "Birlikdə getməyə hazır olan ağıllı, saleh həyat yaşayan, müdrik, çətinliklərə sinə gərən dost tapsan, onunla get, xoşbəxt və diqqətli.",
  "329": "Birlikdə getməyə hazır ağıllı, saleh həyat yaşayan, müdrik dost tapmasan, tək get, fəth elədiyi şahlığından imtina etmiş şah kimi və ya fil meşəsindəki fil kimi.",
  "330": "Tək yaşamaq yaxşıdır. Axmaqla dostluq olmaz. Az arzusu olan kəs, tək get və zülm törətmə, fil meşəsindəki fil kimi.",
  "331": "Dostlar xoşdur, onlara tələbat yarananda. Həzz xoşdur, səbəb olanda. Ölüm saatında yaxşı əməl xoşdur. Bütün dərdlərdən imtina xoşdur.",
  "332": "Bu dünyada analıq xoşdur; atalıq da həmçinin xoşdur; bu dünyada zahidlik xoşdur; brahmanalıq da həmçinin xoşdur.",
  "333": "Qocalığa qədər uzanan mərifət xoşdur; kök atmış iman xoşdur; müdrikliyə çatmaq xoşdur; şərdən arınmaq xoşdur.",
  "chap24": "Müxtəlif",
  "334": "Qafil yaşayan insanın arzuları maluva kimi böyüyür. O, mövcudluqdan mövcudluğa daşınır, meşədə meyvə axtaran meymun kimi.",
  "335": "Dünyaya bağlılıq adlı bu bədbəxt arzu kimə qalib gələrsə, onun dərdləri məhsuldar birana otu kimi boy verir.",
  "336": "Kim ki, bu dünyada bu bədbəxt, çətin məğlub edilən arzuya qalib gəlir, o kəsin dərdləri şanagüllə yarpağından su damcıları sürüşən təki yox olur.",
  "337": "Sizə dediklərim budur: 'Salam olsun sizə, burda nə qədəriniz yığılıbsa! Arzunun kökünü qopardın, xoş ətirli usira kökünün axtarışlarında birananı qopardığınız təki! Qopardın ki, Mara təkrar-təkrar sizə qalib gəlməsin, sel qamışlığı basan kimi'.",
  "338": "Kökü zədələnməmiş və sağlamdırsa, qopardılmış ağac belə böyüməkdə davam etdiyi kimi, əzab da təkrar-təkrar doğulur, əgər arzuya meyl ləğv olunmayıbsa.",
  "339": "O kəsin ki, həzzlərə yönəlmiş otuz altı axını güclüdür, fikirləri də ehtirasa istiqamətlənmişdir, düzgün baxışlardan yayınmış belə insanı axınlar aparır.",
  "340": "Axınlar hər yerdə axırlar. Lata gur boy verir. Bu çiçəklənmiş latanı görüncə, kəsin onun kökünü müdrikliyin köməyi ilə.",
  "341": "Olur ki, insan şəhvət mühasirəsinə düşür. Həzlərə bağlı olan və səadət axtaran bu insanlar həqiqətən də doğulmaya və qocalmaya məruz qalırlar.",
  "342": "Arzunun qovaladığı insanlar hürküdülmüş dovşan kimi ətrafda qaçışırlar. Kəndir və buxovlarla bağlanmış bu insanlar təkrar-təkrar hələ uzun zaman əzaba qayıdırlar.",
  "343": "Arzunun qovaladığı insanlar hürküdülmüş dovşan kimi ətrafda qaçışırlar. Odur ki, əgər bhikşu ehtirası məhv etmək istəyirsə, qoy, o, arzunu qovub çıxartsın.",
  "344": "O, arzulardan azaddır, ehtiraslardan azaddır, meşə həyatına sadiqdir – amma yenə də arzular ormanına qaçır. Baxın bu insana: azad ola-ola boyunduruğa yüyürür.",
  "345": "Müdriklər demirlər: bu dəmirdən, ağacdan və ya babba otundan düzəldilmiş buxovlar möhkəmdirlər. Axı qadınlara, övladlara yaxud qiymətli daşlardan olan sırğalara ehtiraslı bağlılıq daha möhkəmdir.",
  "346": "Müdriklər deyirlər: bu, aşağı dartan, məkrli, qurtulması çətin olan buxovlar möhkəmdirlər. Onları qıraraq müdriklər səyahət edirlər, ehtiras və həzlərdən imtina edərək, arzusuz.",
  "347": "Ehtirasla qızışmışlar axına düşürlər, hörümçək öz toruna düşən kimi. Müdriklər isə axını məhv edərək, bütün zülmlərdən imtina edərək, arzusuz halda səyahət edərlər.",
  "348": "Mövcudluq selini keçərkən keçmişdən imtina et, gələcəkdən imtina et, onların arasında olanlardan imtina et. Əgər ağıl azadlığa çıxıbsa, nə olur-olsun, sən bir daha doğuluşa və ölümə məruz qalmayacaqsan.",
  "349": "Şaşqın fikirli, güclü ehtiraslı, yalnız ləzzətləri görən insanda arzular daima artır: həqiqətən, o, buxovlarını daha da möhkəmləndirir.",
  "350": "Sakit fikirdə məmnunluq tapan, daima düşünən, xoşagəlməyəni xatırlayan - məhz o, arzulara son qoyacaq, məhz o, Maranın buxovlarını qıracaqdır.",
  "351": "O, kamilliyə çatmışdır, o, qorxusuzdur və onun arzuları da yoxdur; bu qüsursuz, mövcudluğun tikanlarını qopartmışdır; onun bu bədəni sonuncudur.",
  "352": "Onun arzuları yoxdur, o, bağlılıqlardan azaddır, sözlərdə və onların izahında mahirdir; o, hərflərin ardıcıllığını bilir (hansıların əvvəl, hansıların sonra gəlməsini); onu böyük müdrik və böyük insan adlandırırlar. Onun bu bədəni sonuncudur.",
  "353": "Mən hər şeyə qalib gəldim, mən hər şeyi bilirəm; istənilən dhammada mən ləkəsizəm. Mən hər şeydən imtina etdim, arzuların məhvi ilə isə azadlığa çıxdım. Özümdən öyrəndiyim halda, kimi müəllimim saya bilərəm ki?",
  "354": "Dhammanın neməti bütün nemətlərdən üstündür; dhammanın şirinliyi hər şirinlikdən üstündür; dhammanın sevinci hər sevincdən üstündür; arzuların məhvi bütün dərdlərə qalib gəlir.",
  "355": "Var-dövlət axmaqları məhv edir, o biri sahili axtaranları yox. Var-dövlət arzusunda axmaq özünü başqalarını öldürən kimi öldürür.",
  "356": "Alaq tarlaları korlayır, ehtiras bu adamları korlayır. Odur ki, ehtirasdan qurtulmuşlara verilən böyük meyvə gətirir.",
  "357": "Alaq tarlaları korlayır, nifrət bu adamları korlayır. Odur ki, nifrətdən qurtulmuşlara verilən böyük meyvə gətirir.",
  "358": "Alaq tarlaları korlayır, axmaqlıq bu adamları korlayır. Odur ki, axmaqlıqdan qurtulmuşlara verilən böyük meyvə gətirir.",
  "359": "Alaq tarlaları korlayır, arzu bu adamları korlayır. Odur ki, arzudan qurtulmuşlara verilən böyük meyvə gətirir.",
  "chap25": "Bhikşu",
  "360": "Gözün pəhrizi yaxşıdır, qulağın pəhrizi yaxşıdır, burunun pəhrizi yaxşıdır, dilin pəhrizi yaxşıdır.",
  "361": "Bədənin pəhrizi yaxşıdır, nitqin pəhrizi yaxşıdır, fikrin pəhrizi yaxşıdır, hər şeydə pəhriz yaxşıdır. Hər şeydə pəhrizkar olan bhikşu bütün dərdlərdən qurtulur.",
  "362": "Əlini idarə edən, ayağını idarə edən, nitqini idarə edən, kamil idarə olunandır, daxilən sevinclidir, toparlanmışdır, tənhadır və məmnundur, bax beləsini bhikşu adlandırırlar.",
  "363": "Ağızını nəzarətdə saxlayan, müdrikcəsinə düşünən, təkəbbürlü olmayan, mənanı və dhammanı izah edən bhikşunun nitqi şirindir.",
  "364": "Dhammada yaşayan, dhammaya heyrət edən, dhammanı zikr edən, dhammanı xatırlayan bhikşu həqiqi dhammadan ayrı düşməz.",
  "365": "Qoy, o, nəsibinə ikrahla yanaşmasın; başqalarınkına həsəd aparmasın. Zira, başqalarına həsəd aparan bhikşu fikrin toparlanmasına nail ola bilmir.",
  "366": "Özündəki az olsa belə, ona ikrahla yanaşmayan, təmiz həyat tərzi sürən və tənbəl olmayan bhikşunu göy əhli tərifləyər.",
  "367": "Özünü ad və forma ilə eyniləşdirməyən, heç nəyi olmaya-olmaya qüssələnməyəni, məhz beləsini bhikşu adlandırırlar.",
  "368": "Xeyirsevərlikdə yaşayan, Buddanın təliminə inanan bhikşu sakit yerə, səadətə, təbii arzuların kəsilməsinə yetişəcəkdir.",
  "369": "Ey bhikşu! Bu gəmini boşalt; səndən azad olunca o, asan hərəkət edəcək. Ehtiras və nifrəti məhv edərək sən Nirvanaya yetişəcəksən.",
  "370": "Beşi kəs, beşdən imtina et, beşin üzərinə yüksəl! Beş bağlılığı dəf etmiş bhikşu 'seli keçmiş' sayılır.",
  "371": "Zikr elə, ey bhikşu, yelbeyin olma; fikirlərinə hissi axınlarda dolaşmağa imkan vermə ki, sən qafilə sonra dəmir kürə udmaq və odda yanaraq: 'Nə yaman əzabdır!' – deyə çığırmaq nəsib olmasın.",
  "372": "Bilməyənin zikri olmur; zikr etməyənin biliyi olmur. Kimin ki, həm zikri, həm biliyi var, o, həqiqətən, Nirvanaya yaxındır.",
  "373": "Sakitləşmiş ağılla tənhalığa çəkilən bhikşu fövqəlinsani həzz alır: o, dhammanı aydın görür.",
  "374": "Hər dəfə o elementlərin yaranmasını və dağılmasını bütün tamlığı ilə dərk edəndə o, bu ölümsüzlüyü bilən, sevinc və səadətə qovuşur.",
  "375": "Müdrik bhikşu üçün başlanğıc burdadır: hisslərin müşahidəsi, qanuna müvafiq şəkildə məmnunluq və pəhrizkarlıq; təmiz həyat sürən və tənbəl olmayan, nəcib dostun arxasınca get.",
  "376": "Qoy, o, həyatda xeyirsevər və vəzifələrini yerinə yetirməkdə kamil olsun. Onda sevinclə dolaraq o, əzaba son qoyacaqdır.",
  "377": "Vassika solmuş ləçəklərini tökən kimi siz də, ey bhikşular, ehtiras və nifrətdən eləcə azad olmalısınız.",
  "378": "O bhikunu sakit adlandırırlar ki, onun bədəni sakitdir, nitqi sakitdir, ağlı sakitdir, özü zikrdədir və dünya nemətlərindən imtina etmişdir.",
  "379": "Özün özünü mahmızla, özün özünü yoxla. Özünü nəzarətdə saxlayan, toparlanmış belə bhikşu xoşbəxt yaşayacaqdır.",
  "380": "Zira, özün özünün ağası, özün özünə pənahsan. Bu səbəbdən də özünü ram et, tacir yaxşı atı ram edən təki.",
  "381": "Qoy, sevinclə dolu, Buddanın təliminə əmin olan bhikşu sakit yerə, səadətə, təbii arzuların kəsilməsinə qovuşsun.",
  "382": "Gənc olmağına baxmayaraq, bhikşu Buddanın təliminə üz tutur və bu dünyanı buluddan qurtulmuş ay kimi işıqlandırır.",
  "chap26": "Brahmanlar (Arhatlar)",
  "383": "Axını durdur, irəli get, arzuları qov, ey brahmana! Yaradılmışların məhvini dərk etdinsə, yaradılmamışı tanımış olacaqsan, ey brahmana!",
  "384": "Brahmana iki dhammada qarşı sahilə çatırsa, ondan, bu 'bilən'dən bütün buxovlar açılır.",
  "385": "Mən o kəsi brahmana adlandırıram ki, onun üçün nə bu sahil var, nə o sahil, nə də ikisi birlikdə, o kəs ki, qorxusuzdur və bağlılıqlardan azaddır.",
  "386": "Mən o kəsi brahmana adlandırıram ki, o, düşünür, ehtiraslardan azaddır, sakitdir, öz işini görür, arzuları dəf edir, o kəs ki, ali xeyirə qovuşmuşdur.",
  "387": "Günəş gündüz parlayır, ay gecə işıqlanır. Döyüşçü zirehdə işıq saçır, brahmana zikrdə. Lakin gecə də, gündüz də parlaq işıq saçır nurlanmış.",
  "388": "Zülmün daşını atan brahmana adlanır; sakitlikdə yaşayan zahid; öz çirkini atmış 'təmizlənmiş' sayılır.",
  "389": "Heç kəs brahmanaya hücum etməməlidir, lakin heç bir brahmana da, qoy, öz qəzəbini zülmkarın üzərinə tökməsin. Brahmananı vurana ayıb olsun, lakin qəzəbini zülmkarının üzərinə tökmüşə daha böyük ayıb olsun.",
  "390": "Brahmana üçün ağlını xoşagələn şeylərdən çəkindirməkdən daha yüksək heç nə yoxdur. İncitmək arzusu yoxa çıxan yerdə əzab da qurtarır.",
  "391": "Mən o kəsi brahmana adlandırıram ki, o, nə bədəni ilə, nə sözü ilə, nə də fikri ilə zülm etməmişdir – özünü bu üç şeydə nəzarətdə saxlayanı.",
  "392": "Kamil nurlanmış birisindən dhammanı öyrəndiyimiz zaman o kəsə gərəkən sayğılar göstərmək lazımdır, brahmana qurbangahın oduna sayğı ilə yanaşdığı kimi.",
  "393": "Dolaşıq saçlara, əsil-nəcabətə yaxud doğuluşuna görə brahmana olmurlar. Həqiqət və dhamma kimdədirsə, o kəs xoşbəxtdir və o, brahmanadır.",
  "394": "Dolaşıq saçlardan sənə nə fayda var, ay axmaq?! Dəridən paltarda sənə nə fayda var?! Axı daxilində cəngəllik var, sənsə yalnız xarici görkəmin barədə düşünürsən.",
  "395": "Tozlu paltarlar geyən, arıqlığından damarları üzə çıxmış, meşədə zikr edən tənha insanı mən brahmana adlandırıram.",
  "396": "Lakin mən insanı yalnız doğuluşuna görə və ya anasına görə brahmana adlandırmıram. Bağlılıqları olanın adı 'bho deyən'dir. Mənsə o kəsi brahmana adlandırıram ki, bağlılıqlardan azaddır və fəqirdir.",
  "397": "Mən o kəsi brahmana adlandırıram ki, o, buxovları qırmış və o, həqiqətən də, qorxudan əsmir, bağlılıqları aşmış və tərki-dünya olmuşdur.",
  "398": "Mən o nurlanmışı brahmana adlandırıram ki, o, maneələri aradan qaldırmış və kəməri, qamçını və zəncirli yüyəni qırmışdır.",
  "399": "O kəsi mən brahmana adlandırıram ki, o, günahkar olmaya-olmaya iradlara, cəzalara, həbslərə səbr edir, o kəsin ki, səbri gücdür, güc isə qoşundur.",
  "400": "O kəsi mən brahmana adlandırıram ki, o, qəzəbdən azaddır, əhdinə sadiqdir, xeyirxahdır və şəhvətsizdir, o kəs ki, çəkingəndir və onun üçün bu bədən axırıncıdır.",
  "401": "O kəsi mən brahmana adlandırıram ki, o, hissi həzlərə yapışmır, su şanagüllə yarpağına yaxud xardal toxumu bizin ucuna yapışmayan kimi.",
  "402": "O kəsi mən brahmana adlandırıram ki, o, yükü yerə qoymuş və sarsılmazdır, o kəs ki, hətta bu dünyada öz əzablarının sonunu bilir.",
  "403": "O kəs ki, müdrikdir, bilikləri dərindir, doğru yolu və yanlış yolu bilir və ali xeyirə qovuşmuşdur, məhz onu mən brahmana adlandırıram.",
  "404": "O kəs ki, arzusuzdur, evi yoxdur, nə ev sahibləri, nə evsizlərlə bağlı deyil, onu mən brahmana adlandırıram.",
  "405": "O kəs ki, öldürmür və öldürməyə də vadar etmir, o kəs ki, qorxaq və ya güclü olmasından asılı olmayaraq canlı məxluqlara ağac qaldırmır, onu mən brahmana adlandırıram.",
  "406": "O kəs ki, həyəcanlılar içərisində həyəcansız, ağac qaldıranlar içərisində sakit qalır, dünyaya bağlılar içərisində bağlılıqlardan azaddır, onu mən brahmana adlandırıram.",
  "407": "O kəsdən ki, ehtiras da, nifrət də, təkəbbür də, riyakarlıq da xardal dənəsi bizin ucundan asanlıqla düşən kimi düşür, onu mən brahmana adlandırıram.",
  "408": "Doğru, ibrətamiz, yumşaq sözlər deyən, nitqi ilə heç kəsi yaralamayan insanı mən brahmana adlandırıram.",
  "409": "Mən o kəsi brahmana adlandırıram ki, o bu dünyada verilməmişi almır, uzun ya qısa, balaca ya böyük, xeyirli ya ziyanlı.",
  "410": "Mən o kəsi brahmana adlandırıram ki, onun nə bu dünya ilə, nə də o birisi ilə bağlı arzusu yoxdur, o, arzusuz və azaddır.",
  "411": "Mən o kəsi brahmana adlandırıram ki, onun arzusu yoxdur, biliyin köməyi ilə şübhələrdən qurtulmuş və ölümsüzlükdə bərqərar olmuşdur.",
  "412": "Mən o kəsi brahmana adlandırıram ki, o, burada həm yaxşıya, həm də pisə olan bağlılığı aşmış, qüssəsiz, ehtirassız və təmizdir.",
  "413": "Mən o kəsi brahmana adlandırıram ki, o, ay kimi ləkəsiz, təmiz, həyəcansızdır, onun yaşamaq sevinci sönmüşdür.",
  "414": "Mən o kəsi brahmana adlandırıram ki, o, bu palçıqlı, çətin yolu, sansaranı, aldanışı aşmış, üzərək o biri sahilə yetişmişdir, o, düşüncəlidir, arzulardan azaddır və şübhələrdən xalidir, bağlılıqları yoxdur və sakitdir.",
  "415": "Mən o kəsi brahmana adlandırıram ki, o, evsiz, burada ehtirasdan imtina edərək ətrafda gəzişir, onun yaşamaq sevinci sönmüşdür.",
  "416": "Mən o kəsi brahmana adlandırıram ki, o, evsiz, burada arzudan imtina edərək ətrafda gəzişir, onun yaşamaq sevinci sönmüşdür.",
  "417": "Mən o kəsi brahmana adlandırıram ki, o, insani bağları tərk edərək, göy bağlılıqlarını da dəf etmişdir, o, bütün bağlılıqlardan arınmışdır.",
  "418": "Bütün aləmlərə qalib gəlmiş, xoş və naxoş olandan imtina etmiş, soyuqqanlı olan və özünün yeni doğuluşa olan yolunu kəsən birisini mən brahmana adlandırıram.",
  "419": "Canlı məxluqların ölümü və doğuluşu barədə hər şeyi bilən, bağlılıqlardan azad və nurlanmış olanı, Suqata olanı mən brahmana adlandırıram.",
  "420": "O kəsin ki, nəsibini nə göy əhli, nə qandharvlar, nə də insanlar bilir, arzuları yox olmuş Arhatı mən brahmana adlandırıram.",
  "421": "Bağlılıqlardan azad və heç nəyi olmayanı, nə keçmişində, nə gələcəyində, nə də indidə bağlanacağı bir şeyi olmayanı mən brahmana adlandırıram.",
  "422": "Öküz kimi güclü, nəcib, cəsarətli, qəhhar olanı, böyük müdrikliyə malik olanı, arzusuz, kamil və nurlanmış olanı mən brahmana adlandırıram.",
  "423": "Əvvəlki mövcudluğunu biləni, cənnəti və cəhənnəmi görəni, kamil bilik sahibi olan, müdrikcəsinə doğulmaların sonunu kəsəni, etmək mümkün olanın hamısını etmişi mən brahmana adlandırıram."
};
